var f = this, id = f.get_id(), v = f._language == 'v', d1 = f.getItemValue('ngay_thay_doi'), d2 = f.getItemValue('ngay_thay_doi2');
if (d2 != null && d1 > d2) {
  var e = 'ngay_thay_doi2';
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(String.format($df.getResources(f._language, 'Message.RequiredField'), f.getItem(e).field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', f.get_id(), e));
}

script.text:

function load$BSPlannedForm(f) {
  f.add_onResponseComplete(on$BSPlannedForm$ResponseComplete);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  set$BSPlannedFormDefaultValue(f);
}
function scatter$BSPlannedForm(f) {set$BSPlannedFormDefaultValue(f);}
function close$BSPlannedForm(f) {
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.remove_onResponseComplete(on$BSPlannedForm$ResponseComplete);} catch (ex) {}
}
function on$BSPlannedForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'MinimumSalary':
      f.setItemValues('luong_toi_thieu, ty_le_bhxh, ty_le_bhyt, ty_le_bhtn', [result[0].Value, result[1].Value, result[2].Value, result[3].Value]);
      onChange$BSPlannedForm$MinimumSalary(f);
      break;
    default:
      break;
  }
}
function set$BSPlannedFormDefaultValue(f) { 
  if (f._action == 'New') {
    f.setItemValue('ngay_thay_doi', new Date());
    f.setItemValue('luong_toi_thieu', f._defaultSalary);
    onChange$BSPlannedForm$MinimumSalary(f);
  }
  var a = ['hs_luong', 'hs_pc_chuc_vu', 'hs_pc_vuot_khung', 'hs_pc_tham_nien', 'hs_pc_khu_vuc', 't_he_so', 'luong_toi_thieu'], v = (f._salaryType != '1');
  for (var i = 0; i < a.length; i++) {
    f.getItem(a[i]).disabled = v;
  }
}
function onChange$BSPlannedForm$StartDate(f) {f.request('MinimumSalary', 'MinimumSalary', ['stt_rec', 'ngay_thay_doi']);}
function onChange$BSPlannedForm$MinimumSalary(f, o) {
  if ((f._salaryType == '1') && (f.getItemValue('t_he_so') != 0)) {
    f.executeExpression(['[luong_co_ban]:=[t_he_so]*[luong_toi_thieu]']);
    onChange$BSPlannedForm$BaseSalary(f);
    if (o) {
      if (o.field.Name == 'luong_toi_thieu') f.live(f.getItem('luong_co_ban'));
    }
  }
}
function onChange$BSPlannedForm$BaseSalary(f) {
  var a = [['ty_le_bhxh', 'tien_bhxh'], ['ty_le_bhyt', 'tien_bhyt'], ['ty_le_bhtn', 'tien_bhtn'], ['ty_le_kpcd', 'tien_kpcd']];
  for (var i = 0; i < a.length; i++) {
    onChange$BSPlannedForm$Rate(f.getItem(a[i][0]), a[i][1]);
  }
}
function onChange$BSPlannedForm$Coefficient(f, o) {
  f.executeExpression(['[t_he_so]:=[hs_luong]+[hs_pc_chuc_vu]+[hs_pc_vuot_khung]/100+[hs_pc_tham_nien]/100+[hs_pc_khu_vuc]'];
  onChange$BSPlannedForm$MinimumSalary(f);
  if (o) {
    if (o.field.Name == 'hs_pc_tham_nien') f.live(f.getItem('t_he_so'));
  }
}
function onChange$BSPlannedForm$Rate(o, c) {
  var f = o.parentForm;
  e = '[' + c + ']:=[' + o.field.Name + ']*[luong_co_ban]/100';
  f.executeExpression([e]);
  f.live(f.getItem(c));
}
function onChange$Voucher$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['cap_bac', 'ty_le_bhxh']);}
